import React from "react";
import axios from "axios";

class Data extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      ip: "",
      data: "",
      loggedIn: false,
      isLoading: false,
      lastLoginFailed: false,
    };
  }

  getClockData() {
    if (this.state.ip !== "") {
      axios
        .get("http://" + this.state.ip, { timeout: 1000 })
        .then((result) => {
          this.state = { data: result.data, isLoading: false };

          if (this.state.data.NAME === "WallClock") {
            this.state.loggedIn = true;
          }
        })
        .catch((error) => {
          this.state.isLoading = false;
          this.state.lastLoginFailed = true;
        });
    } else {
      this.state.isLoading = false;
      this.state.lastLoginFailed = true;
    }
  }
}

export default Data;
